@using sv_4b2b3d188fcc4eb78fec54af349df300.Services

<div class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionSelected.InvokeAsync(section)">
                    <span class="section-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = { "Profile", "Notifications", "Security", "Appearance" };

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    padding: 1rem 0;
}

.sidebar-title {
    padding: 0 1rem;
    margin-bottom: 1rem;
    font-weight: 600;
    color: #333;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1rem;
    color: #555;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
    cursor: pointer;
    font-size: 0.95rem;
}

.settings-sidebar .nav-link:hover {
    background-color: #f0f0f0;
    color: #333;
}

.settings-sidebar .nav-link.active {
    background-color: #e8f0fe;
    color: #1a73e8;
    border-left-color: #1a73e8;
    font-weight: 600;
}

.section-icon {
    font-size: 1.1rem;
}

@using sv_4b2b3d188fcc4eb78fec54af349df300.Services
@inject ISettingsService SettingsService

<div class="profile-section">
    @if (_loading)
    {
        <p>Loading profile...</p>
    }
    else
    {
        <h4>Profile Settings</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="profile-form">
            <div class="avatar-area mb-3">
                <img src="@_avatarUrl" alt="Avatar" class="avatar-preview" />
                <div class="mt-2">
                    <label class="form-label">Avatar URL</label>
                    <input type="text" class="form-control" @bind="_avatarUrl" />
                </div>
            </div>

            <div class="mb-3">
