@inject ISettingsService SettingsService

<div class="security-section">
    @if (_loading)
    {
        <p>Loading security settings...</p>
    }
    else
    {
        <h4>Security Settings</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

        <hr />

        <div class="mb-4">
            <h6>Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled" disabled />
                    <label class="form-check-label" for="twoFactor">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </label>
                </div>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "✓ Active" : "✗ Inactive")
                </span>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <p class="text-muted small mt-2">
                    Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>

        <hr />

        <div class="mb-3">
            <h6>Active Sessions</h6>
            <div class="table-responsive">
                <table class="table table-hover">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session.Id != _currentSessionId)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        <RevokeSessionDialog Visible="_showRevokeDialog"
                             DeviceName="@(_sessionToRevoke?.Device ?? "")"
                             OnConfirm="ConfirmRevoke"
                             OnCancel="CancelRevoke" />
    }
</div>

@code {
    private bool _loading = true;
    private string? _message;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private string _currentSessionId = "sess-1"; // first session is "current"

    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _lastPasswordChange = DateTime.UtcNow;
        _message = "Password changed successfully!";
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _message = $"Session on {_sessionToRevoke.Device} has been revoked.";
            _sessionToRevoke = null;
        }
        _showRevokeDialog = false;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
        _showRevokeDialog = false;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }
}

