{"file_text": "<div class="change-password-panel">
    <button class="btn btn-outline-secondary mb-3 panel-toggle" @onclick="TogglePanel">
        @(_expanded ? "▾" : "▸") Change Password
    </button>

    @if (_expanded)
    {
        <div class="password-form">
            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="alert alert-danger">@_error</div>
            }
            @if (!string.IsNullOrEmpty(_success))
            {
                <div class="alert alert-success">@_success</div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @(_saving ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private bool _saving;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private string? _success;

    private void TogglePanel() => _expanded = !_expanded;

    private async Task UpdatePasswordAsync()
    {
        _error = null;
        _success = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _error = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 6)
        {
            _error = "New password must be at least 6 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _error = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _success = "Password updated successfully!";
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _saving = false;
    }
}
