                    <div class="preview-header">Sample Header</div>
                    <p class="preview-text">
                        This is a preview of how your content will look with the selected settings.
                    </p>
                    <div class="preview-card">
                        <strong>Card Title</strong>
                        <p>Card content with your chosen theme and font size.</p>
                    </div>
                    <button class="preview-button">Sample Button</button>
                </div>
            </div>
