toolArgs.file_text:
.appearance-section h4 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.preview-area {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.5rem;
    transition: all 0.2s ease;
    min-height: 250px;
}

/* Theme variants */
.preview-light {
    background-color: #ffffff;
    color: #212529;
}

.preview-dark {
    background-color: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #333;
}

/* Font size variants */
.preview-font-sm { font-size: 0.85rem; }
.preview-font-md { font-size: 1rem; }
.preview-font-lg { font-size: 1.2rem; }

/* Compact mode */
.preview-compact {
    padding: 0.75rem;
    line-height: 1.2;
}

.preview-compact .preview-card {
    padding: 0.5rem;
    margin: 0.5rem 0;
}

.preview-header {
    font-size: 1.2em;
    font-weight: 600;
    margin-bottom: 0.75rem;
    padding-bottom: 0.5rem;
    border-bottom: 2px solid currentColor;
    opacity: 0.8;
}

.preview-text {
    margin-bottom: 1rem;
    opacity: 0.7;
}

.preview-card {
    padding: 1rem;
    border-radius: 0.375rem;
    margin-bottom: 1rem;
}

.preview-light .preview-card {
    background-color: #f8f9fa;
    border: 1px solid #dee2e6;
}

.preview-dark .preview-card {
    background-color: #313244;
    border: 1px solid #45475a;
}

.preview-button {
    padding: 0.375rem 0.75rem;
    border-radius: 0.25rem;
    border: none;
    font-weight: 500;
    cursor: default;
}

.preview-light .preview-button {
    background-color: #0d6efd;
    color: white;
}

.preview-dark .preview-button {
    background-color: #89b4fa;
    color: #1e1e2e;
}

.preview-system .preview-button {
    background-color: #6c757d;
    color: white;
}

