arguments.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <div class="settings-nav">
        <SettingsSidebar ActiveSection="@_activeSection"
                         OnSectionSelected="section => _activeSection = section" />
    </div>

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    background: #fff;
}

.settings-nav {
    width: 220px;
    min-width: 220px;
    border-right: 1px solid #dee2e6;
    background: #f8f9fa;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

